import{_ as a,o as i,c as l,ag as o}from"./chunks/framework.CAXxHpAX.js";const h=JSON.parse('{"title":"通用配置原则","description":"","frontmatter":{},"headers":[],"relativePath":"guide/common-principles.md","filePath":"guide/common-principles.md"}'),r={name:"guide/common-principles.md"};function t(d,e,p,c,s,n){return i(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="通用配置原则" tabindex="-1">通用配置原则 <a class="header-anchor" href="#通用配置原则" aria-label="Permalink to &quot;通用配置原则&quot;">​</a></h1><p>在配置任何工具之前,先了解这些通用原则,可以帮助你避免常见错误。</p><h2 id="_1-先确认-api-key-和-base-url" tabindex="-1">1. 先确认 API Key 和 Base URL <a class="header-anchor" href="#_1-先确认-api-key-和-base-url" aria-label="Permalink to &quot;1. 先确认 API Key 和 Base URL&quot;">​</a></h2><p>在打开工具设置之前,先确认你已经:</p><ul><li>获得了有效的 API Key</li><li>知道正确的 Base URL(如 <code>https://api.1010101.asia/</code>)</li></ul><p>如果这两个信息有误,后续配置都不会成功。</p><h2 id="_2-注意字段名称" tabindex="-1">2. 注意字段名称 <a class="header-anchor" href="#_2-注意字段名称" aria-label="Permalink to &quot;2. 注意字段名称&quot;">​</a></h2><p>不同工具对相同概念可能使用不同的字段名:</p><ul><li>API Key 可能叫 <code>apiKey</code>、<code>api_key</code>、<code>API Key</code>、<code>Key</code> 等</li><li>Base URL 可能叫 <code>baseURL</code>、<code>base_url</code>、<code>Base URL</code>、<code>API Endpoint</code> 等</li></ul><p>填写时请以工具页示例为准,不要想当然地猜测字段名。</p><h2 id="_3-不要有多余空格" tabindex="-1">3. 不要有多余空格 <a class="header-anchor" href="#_3-不要有多余空格" aria-label="Permalink to &quot;3. 不要有多余空格&quot;">​</a></h2><p>复制粘贴 API Key 和 Base URL 时,注意不要带入多余空格:</p><ul><li>字符串前后不要有空格</li><li>字符串中间不要有换行</li></ul><p>多余空格会导致验证失败,且很难排查。</p><h2 id="_4-保存后可能需要重启或重新加载" tabindex="-1">4. 保存后可能需要重启或重新加载 <a class="header-anchor" href="#_4-保存后可能需要重启或重新加载" aria-label="Permalink to &quot;4. 保存后可能需要重启或重新加载&quot;">​</a></h2><p>某些工具在修改配置后需要:</p><ul><li>保存配置文件</li><li>重新加载配置(如 Continue 的&quot;Reload config&quot;)</li><li>重启工具</li></ul><p>具体操作请参考对应工具页的说明。</p><h2 id="_5-验证配置是否生效" tabindex="-1">5. 验证配置是否生效 <a class="header-anchor" href="#_5-验证配置是否生效" aria-label="Permalink to &quot;5. 验证配置是否生效&quot;">​</a></h2><p>配置完成后,务必验证是否生效。常见验证方法:</p><ul><li>发送一个简单请求,看是否成功返回</li><li>检查工具的&quot;连接测试&quot;功能</li><li>查看工具日志或调试信息</li></ul><p>验证方法请参考 <a href="/guide/verify.html">如何验证配置是否生效</a>。</p><h2 id="_6-注意平台差异" tabindex="-1">6. 注意平台差异 <a class="header-anchor" href="#_6-注意平台差异" aria-label="Permalink to &quot;6. 注意平台差异&quot;">​</a></h2><p>某些工具在不同平台(Windows、macOS、Linux)上的配置方式略有不同:</p><ul><li>配置文件路径可能不同</li><li>设置入口位置可能不同</li><li>环境变量设置方式可能不同</li></ul><p>工具页会标注重要的平台差异,请注意查看。</p><h2 id="_7-不要混用不同服务商的-api-key-和-base-url" tabindex="-1">7. 不要混用不同服务商的 API Key 和 Base URL <a class="header-anchor" href="#_7-不要混用不同服务商的-api-key-和-base-url" aria-label="Permalink to &quot;7. 不要混用不同服务商的 API Key 和 Base URL&quot;">​</a></h2><p>API Key 和 Base URL 必须来自同一服务商:</p><ul><li>错误:服务商 A 的 API Key + 服务商 B 的 Base URL</li><li>正确:服务商 A 的 API Key + 服务商 A 的 Base URL</li></ul><p>混用会导致身份验证失败。</p><h2 id="_8-保护你的-api-key" tabindex="-1">8. 保护你的 API Key <a class="header-anchor" href="#_8-保护你的-api-key" aria-label="Permalink to &quot;8. 保护你的 API Key&quot;">​</a></h2><p>API Key 是敏感信息,请注意:</p><ul><li>不要分享给他人</li><li>不要提交到公开代码仓库</li><li>不要截图发到公开渠道</li></ul><p>如果 API Key 泄露,立即到服务商控制台撤销并生成新 Key。</p>',34)])])}const _=a(r,[["render",t]]);export{h as __pageData,_ as default};
